/*
# Insert all missing seed data

Inserts programs, semesters, subjects, students, rooms, registrations,
arrear registrations, hall tickets, seat allocations, question papers,
questions, mark entries, revaluation requests, results, and reports.
All foreign keys reference existing department/academic_year/exam_type IDs.
Uses ON CONFLICT DO NOTHING for idempotency.
*/

-- Programs (using e-prefix style but valid hex: 00000002 prefix)
ON CONFLICT (id) DO NOTHING;

-- Semesters
ON CONFLICT (id) DO NOTHING;

-- Subjects (10 subjects: CSE + ECE)
ON CONFLICT (id) DO NOTHING;

-- Exam Rooms (7 rooms)
ON CONFLICT (id) DO NOTHING;

-- Students (20 students across CSE, ECE, MECH)
ON CONFLICT (id) DO NOTHING;

-- Registrations (15 students)

-- Arrear Registrations

-- Hall Tickets (10 tickets)
ON CONFLICT (id) DO NOTHING;

-- Hall Ticket Subjects

-- Seat Allocations (15 seats)

-- Question Papers (7 papers across multiple approval stages)
ON CONFLICT (id) DO NOTHING;

-- Questions (18 questions across subjects)

-- Mark Entries (22 entries across students)
ON CONFLICT (student_id, subject_id, academic_year_id) DO NOTHING;

-- Revaluation Requests

UPDATE revaluation_requests
SET revised_marks = 58
WHERE student_id = '00000007-0000-0000-0000-000000000008'
  AND subject_id = '00000005-0000-0000-0000-000000000008'
  AND status = 'completed';

-- Results (8 records: published, approved, pending)
ON CONFLICT (student_id, academic_year_id, semester_number) DO NOTHING;

-- Reports History (6 records)
