INSERT INTO questions (subject_id, question_text, marks, difficulty) VALUES
  ('00000005-0000-0000-0000-000000000005','Explain the concept of overfitting in machine learning and how regularization techniques address it.',10,'medium'),
  ('00000005-0000-0000-0000-000000000005','What is a confusion matrix? Derive precision, recall, and F1-score with a numerical example.',10,'easy'),
  ('00000005-0000-0000-0000-000000000005','Compare supervised and unsupervised learning with real-world applications.',15,'medium'),
  ('00000005-0000-0000-0000-000000000005','Implement a decision tree classifier from scratch. Explain the Gini impurity criterion.',20,'hard'),
  ('00000005-0000-0000-0000-000000000005','Describe the k-means clustering algorithm step-by-step with a worked example.',15,'medium'),
  ('00000005-0000-0000-0000-000000000006','Explain the TCP/IP protocol stack with a diagram describing the role of each layer.',15,'easy'),
  ('00000005-0000-0000-0000-000000000006','What are the differences between TCP and UDP? Provide two use cases for each protocol.',10,'easy'),
  ('00000005-0000-0000-0000-000000000006','Describe DHCP IP address assignment process including DORA exchange in detail.',15,'medium'),
  ('00000005-0000-0000-0000-000000000006','Explain cloud service models IaaS, PaaS, and SaaS with industry examples.',10,'easy'),
  ('00000005-0000-0000-0000-000000000006','What is serverless computing? Compare AWS Lambda and Azure Functions.',15,'hard'),
  ('00000005-0000-0000-0000-000000000007','What is software engineering? Explain all SDLC phases with a labeled diagram.',10,'easy'),
  ('00000005-0000-0000-0000-000000000007','Compare Waterfall and Agile methodologies. When is each approach preferred?',15,'medium'),
  ('00000005-0000-0000-0000-000000000007','Explain UML class and sequence diagrams with illustrative examples.',15,'medium'),
  ('00000005-0000-0000-0000-000000000009','Explain CMOS fabrication process step-by-step and its advantages over NMOS technology.',20,'hard'),
